const res = $input.first().json;
const rows = res.values || [];
let found = null;
for (let i = 0; i < rows.length; i++) {
  const s = (rows[i][4] || '').toString().toUpperCase().trim();
  if (s === 'PENDING') { found = { idx: i, row: rows[i] }; break; }
}
if (!found) throw new Error('No PENDING topic in Dashboard tab. Set STATUS (col E) = PENDING for a row.');
const sheetRow   = found.idx + 4;
const topic      = (found.row[1] || '').trim();
const difficulty = (found.row[2] || 'beginner').trim();
const durationMin = parseFloat(found.row[3]) || 1;
if (!topic) throw new Error('PENDING row found but Topic (col B) is empty.');
const jobId = (found.row[0] || '').trim() || ('PHY-' + Date.now().toString().slice(-8));
console.log('Row ' + sheetRow + ' | ' + jobId + ' | ' + topic + ' | ' + durationMin + 'min');
return [{ json: { job_id: jobId, topic: topic, difficulty: difficulty, duration_min: durationMin, sheet_row: sheetRow, source: 'google_sheet' } }];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

let sheetData = {};
try { sheetData = $('Pick PENDING Topic').first().json; } catch(e) {}

const jobId    = body.job_id    || raw.job_id    || sheetData.job_id    || ('PHY-' + Date.now().toString().slice(-8));
const topic    = body.topic     || raw.topic     || sheetData.topic;
const sheetRow = body.sheet_row || raw.sheet_row || sheetData.sheet_row || null;

if (!topic) throw new Error('No topic found. Add a PENDING row in Google Sheet Dashboard (col B=topic, col E=PENDING).');

return [{ json: { job_id: jobId, topic: topic, sheet_row: sheetRow, start_time: Date.now() } }];

const data = $input.first().json;
const topic = data.topic;

// Each Seedance clip = 10 seconds max.
// We generate 3 clips => up to 30 seconds of background video.
// Narration target: 20-28 seconds (60-80 words at ~3 words/sec).
// Gemini must split narration into 3 time segments and write
// a matching Seedance video prompt for each segment.

const prompt = `You are a script writer for a physics YouTube Shorts channel.

TOPIC: ${topic}

Create a 20-28 second vertical (9:16) physics YouTube Short.

The video will have THREE background video clips (each ~10 seconds) generated by an AI video model.
Your job is to write:
  1. A narration that flows naturally across all 3 segments
  2. A visual prompt for each segment that MATCHES what is being said

──────────────────────────────────────────────────────────────
NARRATION RULES:
- Total: 60-80 words (spoken at ~3 words/second = ~20-27 seconds)
- Hook the viewer in the FIRST sentence (ask a question or state a shocking fact)
- Conversational tone, no jargon, educational but exciting
- Split mentally into 3 parts: HOOK (0-10s) → EXPLAIN (10-20s) → WOW FACTOR (20-28s)

CLIP PROMPT RULES (very important):
- clip_prompt_1: visuals for the HOOK segment (0-10s) — what the viewer sees while the hook plays
- clip_prompt_2: visuals for the EXPLAIN segment (10-20s) — what the viewer sees during explanation
- clip_prompt_3: visuals for the WOW FACTOR segment (20-28s) — a dramatic visual for the conclusion

Each clip prompt MUST:
- Be 150-250 characters long (detailed and specific)
- Start with: "Cinematic vertical 9:16 video,"
- Describe the PHYSICS CONCEPT visually (not just generic backgrounds)
- Include camera motion (e.g. slow zoom in, pull back, rotating, tracking shot)
- Include lighting style (e.g. dramatic lighting, neon glow, dark background, golden hour)
- Be realistic enough for AI video generation (no text, no people speaking)
- Match the narration content of that specific segment

EXAMPLE clip prompt format:
"Cinematic vertical 9:16 video, extreme slow-motion water droplet hitting a still surface creating perfect circular ripples expanding outward, dark background with dramatic backlighting, shallow depth of field, slow downward camera tilt"

──────────────────────────────────────────────────────────────
Return ONLY a raw JSON object (no markdown, no explanation):
{
  "narration": "Full narration text 60-80 words",
  "narration_segment_1": "Exact words spoken during clip 1 (0-10s)",
  "narration_segment_2": "Exact words spoken during clip 2 (10-20s)",
  "narration_segment_3": "Exact words spoken during clip 3 (20-28s)",
  "clip_prompt_1": "Cinematic vertical 9:16 video, [150-250 char vivid description matching segment 1]",
  "clip_prompt_2": "Cinematic vertical 9:16 video, [150-250 char vivid description matching segment 2]",
  "clip_prompt_3": "Cinematic vertical 9:16 video, [150-250 char vivid description matching segment 3]",
  "title": "YouTube Short title under 60 chars — curiosity-inducing",
  "hashtags": "#physics #science #shorts #learnphysics #physicsfacts"
}`;

return [{ json: { ...data, gemini_script_request: {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: {
    maxOutputTokens: 2048,
    temperature: 0.9,
    responseMimeType: 'application/json',
    thinkingConfig: { thinkingBudget: 0 }
  }
}}}];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content)
  throw new Error('Gemini response empty: ' + JSON.stringify(response).slice(0, 300));

let rawText = response.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(rawText); } catch(e1) {
  const start = rawText.indexOf('{'), end = rawText.lastIndexOf('}');
  const block = (start !== -1 && end !== -1) ? rawText.slice(start, end + 1) : rawText;
  try { parsed = JSON.parse(block); } catch(e2) {
    throw new Error('Failed to parse Gemini JSON: ' + rawText.slice(0, 500));
  }
}

if (!parsed.narration)
  throw new Error('Response missing narration field');

// Build clip_prompts array from individual fields (new format)
// Fall back to old clip_prompts array if Gemini used that format
let clip_prompts = [];
if (parsed.clip_prompt_1 && parsed.clip_prompt_2 && parsed.clip_prompt_3) {
  clip_prompts = [parsed.clip_prompt_1, parsed.clip_prompt_2, parsed.clip_prompt_3];
} else if (Array.isArray(parsed.clip_prompts) && parsed.clip_prompts.length >= 2) {
  clip_prompts = parsed.clip_prompts.slice(0, 3);
} else {
  throw new Error('Gemini did not return clip prompts. Got: ' + JSON.stringify(parsed));
}

const wordCount = parsed.narration.trim().split(/\s+/).length;
console.log('Narration: ' + wordCount + ' words');
console.log('Clip 1 prompt (' + clip_prompts[0].length + ' chars): ' + clip_prompts[0].slice(0,80) + '...');
console.log('Clip 2 prompt (' + clip_prompts[1].length + ' chars): ' + clip_prompts[1].slice(0,80) + '...');
console.log('Clip 3 prompt (' + clip_prompts[2].length + ' chars): ' + clip_prompts[2].slice(0,80) + '...');

return [{ json: {
  ...jobConfig,
  narration:          parsed.narration,
  narration_segment_1: parsed.narration_segment_1 || '',
  narration_segment_2: parsed.narration_segment_2 || '',
  narration_segment_3: parsed.narration_segment_3 || '',
  clip_prompts,
  title:    parsed.title    || jobConfig.topic,
  hashtags: parsed.hashtags || '#physics #science #shorts'
}}];

const https = require('https');
const fs = require('fs');

const data = $input.first().json;
const apiKey = $env.ELEVENLABS_API_KEY;
const voiceId = $env.ELEVENLABS_VOICE_ID;
const jobId = data.job_id;

function httpsPost(hostname, path, headers, bodyStr) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(bodyStr, 'utf-8');
    const req = https.request({ hostname, path, method: 'POST', headers: { ...headers, 'Content-Length': buf.length } }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks).toString() }));
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const body = JSON.stringify({
  text: data.narration,
  model_id: 'eleven_multilingual_v2',
  voice_settings: { stability: 0.5, similarity_boost: 0.8 }
});

const res = await httpsPost('api.elevenlabs.io', '/v1/text-to-speech/' + voiceId + '/with-timestamps', {
  'Content-Type': 'application/json',
  'xi-api-key': apiKey
}, body);

if (res.status !== 200) throw new Error('ElevenLabs error ' + res.status + ': ' + res.body);

const result = JSON.parse(res.body);
const { audio_base64, alignment } = result;

// Save audio
const inputDir = '/data/ffmpeg/input';
if (!require('fs').existsSync(inputDir)) require('fs').mkdirSync(inputDir, { recursive: true });
const audioPath = '/data/ffmpeg/input/' + jobId + '_narration.mp3';
fs.writeFileSync(audioPath, Buffer.from(audio_base64, 'base64'));

// Build word-level subtitle chunks
const chars = alignment.characters;
const starts = alignment.character_start_times_seconds;
const durs = alignment.character_durations_seconds;
const totalDuration = starts[starts.length - 1] + durs[durs.length - 1];

const words = [];
let wChars = '', wStart = null, wEnd = 0;
for (let i = 0; i < chars.length; i++) {
  if (chars[i] === ' ' || chars[i] === '\n') {
    if (wChars.trim()) words.push({ text: wChars.trim(), start: wStart, end: wEnd });
    wChars = ''; wStart = null;
  } else {
    if (wStart === null) wStart = starts[i];
    wEnd = starts[i] + durs[i];
    wChars += chars[i];
  }
}
if (wChars.trim()) words.push({ text: wChars.trim(), start: wStart, end: wEnd });

const chunks = [];
const PER = 5;
for (let i = 0; i < words.length; i += PER) {
  const g = words.slice(i, i + PER);
  chunks.push({ text: g.map(w => w.text).join(' '), start: g[0].start, end: g[g.length-1].end + 0.1 });
}

const subsPath = '/data/ffmpeg/input/' + jobId + '_subs.json';
fs.writeFileSync(subsPath, JSON.stringify(chunks));

return [{ json: { ...data, audio_path: audioPath, subs_path: subsPath, audio_duration: totalDuration, subtitle_chunks: chunks } }];
